  <HEADER encrypted="1" encrypted_ver="1" build="0.0704.1001.0000.13.0" user="z" computer="DESKTOP-LC5V468" date="2025.05.17 10'54'17" map_xs="98" map_ys="98" north_angle="0" extra_map_edge="1" tileset="volcanic" environment="Volcanic_final" players="4" name="Адские горы" id="(4)Fire Crossings" style="0" description="До недавнего времени, в эту гористую, воистину адскую местность, полюбившуюся рудокопам винчи большими залежами тимония, вел узкий мост, уничтоженный местными лавовыми тварями. Кондотьеры так же не смогли противостоять здешней фауне, из-за чего поначалу успешные разработки тимония были свернуты. Были замечены и разбойники дюн, наживающиеся на путешественниках, проходящих через эти земли. &#xA; {— От Матвея Icpompeo Аль-Бороди.}" enable_dominance="1" preview_image_ext="tga" version="12" allowable_game_styles="4294967295" default_game_style="-1" victory="0" elimination="1" allies="0" living_world_bird="22" force_rush_rules_disable="0" does_override_teamstyle="0" teamstyle_override_value="0" starts_required="0" starts_no_pick="0" show_all_villages="1" generate_script="0" num_villages="0" num_special="0" num_villages_override="13" num_special_override="10-14">
